    notes.Add(new ResearchNote(title, content));
    Console.WriteLine($"  📝 Note saved: \"{title}\"");
    return $"Note #{notes.Count} saved: \"{title}\"";
}

// ---------------------------------------------------------------------------
// Tool: ReadNotes – retrieves all notes collected so far
// ---------------------------------------------------------------------------
[Description("Read all research notes taken so far in this session.")]
string ReadNotes()
{
    if (notes.Count == 0)
        return "No notes have been taken yet.";

    Console.WriteLine($"  📖 Reading {notes.Count} note(s)");
    var sb = new StringBuilder();
    for (int i = 0; i < notes.Count; i++)
    {
        sb.AppendLine($"--- Note #{i + 1}: {notes[i].Title} ---");
        sb.AppendLine(notes[i].Content);
        sb.AppendLine();
    }
    return sb.ToString();
}

// --- Build AI Chat Client ---
OpenAIClientOptions? clientOptions = null;
if (!string.IsNullOrWhiteSpace(endpoint))
    clientOptions = new OpenAIClientOptions { Endpoint = new Uri(endpoint) };

IChatClient chatClient = new OpenAIClient(
        new System.ClientModel.ApiKeyCredential(apiKey), clientOptions)
    .GetChatClient(modelId)
    .AsIChatClient();

// --- Register tools ---
var tools = new AIFunction[]
{
    AIFunctionFactory.Create(SearchWeb),
    AIFunctionFactory.Create(TakeNote),
    AIFunctionFactory.Create(ReadNotes),
};

var chatOptions = new ChatOptions
{
    Tools = [.. tools],
    Temperature = 0.3f,
};

// --- System prompt ---
const string systemPrompt = """
    You are an AI research agent. Given a topic, you thoroughly research it
    using the available tools and produce a well-organized summary.

    ## Research Process
    1. Break the topic into key aspects worth investigating.
    2. Use SearchWeb with varied queries to gather information from multiple angles.
    3. Use TakeNote to record important facts, statistics, and insights you discover.
    4. After sufficient research (at least 3–4 searches), use ReadNotes to review.
    5. Synthesize your notes into a comprehensive, well-structured summary.

    ## Guidelines
    - Search for different facets: history, current state, key facts, examples.
    - Always take notes on valuable findings before moving to the next search.
    - Cite sources when possible.
    - Your final summary should be thorough yet concise.
    """;

// === Interactive loop ===
Console.WriteLine("╔══════════════════════════════════════╗");
Console.WriteLine("║       🔬 AI Research Agent           ║");
Console.WriteLine("╠══════════════════════════════════════╣");
Console.WriteLine("║  Enter a topic to research, or       ║");
Console.WriteLine("║  type 'quit' to exit.                ║");
Console.WriteLine("╚══════════════════════════════════════╝");
Console.WriteLine();

while (true)
{
    Console.Write("Research topic> ");
    var topic = Console.ReadLine()?.Trim();
    if (string.IsNullOrEmpty(topic) || topic.Equals("quit", StringComparison.OrdinalIgnoreCase))
        break;

    notes.Clear();
    Console.WriteLine($"\n🔬 Researching: \"{topic}\"\n");

    var messages = new List<ChatMessage>
    {
        new(ChatRole.System, systemPrompt),
        new(ChatRole.User,
            $"Research the following topic and provide a comprehensive summary:\n\n{topic}"),
    };

    const int maxIterations = 25;
    int iteration = 0;

    while (iteration++ < maxIterations)
    {
        ChatResponse response = await chatClient.GetResponseAsync(messages, chatOptions);

        // Append assistant messages to the conversation
        messages.AddRange(response.Messages);

        // Collect any function-call requests from the response
        var calls = response.Messages
            .SelectMany(m => m.Contents)
            .OfType<FunctionCallContent>()
            .ToList();

        if (calls.Count == 0)
        {
            // No tool calls → the model has produced its final answer
            Console.WriteLine();
            Console.WriteLine(new string('═', 60));
            Console.WriteLine("📋 RESEARCH SUMMARY");
            Console.WriteLine(new string('═', 60));
            Console.WriteLine(response.Text);
            Console.WriteLine(new string('═', 60));
            break;
        }

        // Execute each requested tool and feed results back
        foreach (var call in calls)
        {
            var fn = tools.FirstOrDefault(t => t.Name == call.Name);
            object? result = fn is not null
                ? await fn.InvokeAsync(call.Arguments)
                : $"Unknown tool: {call.Name}";

            messages.Add(new ChatMessage(ChatRole.Tool,
                [new FunctionResultContent(call.CallId, result)]));
        }
    }

    if (iteration > maxIterations)
        Console.WriteLine("\n⚠️  Reached the maximum number of agent iterations.");

    Console.WriteLine();
}

Console.WriteLine("Goodbye! 👋");

// --- Supporting types ---
record ResearchNote(string Title, string Content);

