 using System.ComponentModel;
 using System.Text;
 using System.Text.Json;
 using Microsoft.Extensions.AI;
 using OpenAI;

 // --- Configuration ---
 var endpoint = Environment.GetEnvironmentVariable("OPENAI_ENDPOINT");
 var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
     ?? throw new InvalidOperationException(
         "Set the OPENAI_API_KEY environment variable to your OpenAI (or compatible) API key.");
 var modelId = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini";

 // --- Shared state for tools ---
 var notes = new List<ResearchNote>();
 using var http = new HttpClient();
 http.DefaultRequestHeaders.UserAgent.ParseAdd("ResearchAgent/1.0");

 // ---------------------------------------------------------------------------
 // Tool: SearchWeb – queries DuckDuckGo's instant-answer API (free, no key)
 // ---------------------------------------------------------------------------
 [Description("Search the web for information on a query. Returns summaries and related results.")]
 async Task<string> SearchWeb([Description("The search query")] string query)
 {
     Console.WriteLine($"  🔍 Searching: \"{query}\"");
     try
     {
         var url = $"https://api.duckduckgo.com/?q={Uri.EscapeDataString(query)}"
                 + "&format=json&no_html=1&skip_disambig=1";
         var json = await http.GetStringAsync(url);
         using var doc = JsonDocument.Parse(json);
         var root = doc.RootElement;

         var sb = new StringBuilder();

         var abstractText = root.GetProperty("AbstractText").GetString();
         if (!string.IsNullOrWhiteSpace(abstractText))
         {
             sb.AppendLine($"[Summary] {abstractText}");
             sb.AppendLine($"[Source]  {root.GetProperty("AbstractSource").GetString()} – "
                         + root.GetProperty("AbstractURL").GetString());
             sb.AppendLine();
         }

         if (root.TryGetProperty("RelatedTopics", out var topics))
         {
             int count = 0;
             foreach (var topic in topics.EnumerateArray())
             {
                 if (topic.TryGetProperty("Text", out var text)
                     && !string.IsNullOrWhiteSpace(text.GetString()))
                 {
                     sb.AppendLine($"• {text.GetString()}");
                     if (topic.TryGetProperty("FirstURL", out var u))
                         sb.AppendLine($"  URL: {u.GetString()}");
                     if (++count >= 8) break;
                 }

                 if (topic.TryGetProperty("Topics", out var sub))
                 {
                     foreach (var st in sub.EnumerateArray())
                     {
                         if (st.TryGetProperty("Text", out var stText))
                         {
                             sb.AppendLine($"• {stText.GetString()}");
                             if (++count >= 8) break;
                         }
                     }
                 }
             }
         }

         return sb.Length > 0
             ? sb.ToString()
             : "No results found. Try a different or more specific query.";
     }
     catch (Exception ex)
     {
         return $"Search failed: {ex.Message}. Try a different query.";
     }
 }

